insert into questions (chapter_id, question, option_a, option_b, option_c, option_d, option_e, correct_option, explanation, difficulty) values
('b0000000-0000-4000-8000-050100000000', 'Sejak tanggal berapa Indonesia merdeka, yang menjadi titik awal perjalanan bangsa yang diwarnai dinamika politik hingga saat ini?', '17 Agustus 1945', '18 Agustus 1945', '1 Juni 1945', '20 Mei 1908', null, 'A', 'Indonesia merdeka sejak Proklamasi 17 Agustus 1945, dan lebih dari 72 tahun perjalanannya diwarnai dinamika/kemelut politik yang mengganggu stabilitas nasional.', 'easy'),
('b0000000-0000-4000-8000-050100000000', 'Istilah apa yang digunakan untuk menggambarkan bangsa Indonesia sebagai masyarakat dengan kesatuan spirit/karakter, di mana keberagaman budaya, adat, bahasa, dan agama tetap dipertahankan (bukan diseragamkan)?', 'Karakter Gesellschaft', 'Karakter Gemeinschaft', 'Karakter Nasionalis', 'Karakter Monodualistis', null, 'B', 'Bangsa dimaknai sebagai masyarakat dengan kesatuan spirit/karakter (Karakter Gemeinschaft); keberagaman budaya/adat/bahasa/agama tetap dipertahankan, bukan diseragamkan.', 'medium'),
('b0000000-0000-4000-8000-050100000000', 'Siapa sebutan bagi para tokoh yang merumuskan nilai-nilai kebangsaan sebagai landasan pembentukan dan penyelenggaraan negara Indonesia?', 'Dewan Konstituante', 'Panitia Sembilan', 'The Founding Fathers', 'Komite Nasional Indonesia Pusat', null, 'C', 'Para pendiri bangsa (the Founding Fathers) merumuskan nilai-nilai kebangsaan sebagai landasan pembentukan & penyelenggaraan negara.', 'easy'),
('b0000000-0000-4000-8000-050100000000', 'Reformasi, sebagaimana dijelaskan dalam latar belakang modul ini, dimaknai sebagai proses apa bagi bangsa Indonesia?', 'Perubahan bentuk negara dari kesatuan menjadi federal', 'Kembali ke sistem UUDS 1950 secara utuh', 'Penghapusan seluruh lembaga negara warisan Orde Baru', 'Reinventing, rebuilding, dan konsolidasi demokrasi, dari prosedural menuju kultural dan substantif', null, 'D', 'Reformasi dimaknai sebagai proses reinventing, rebuilding, dan konsolidasi demokrasi bangsa Indonesia, dari prosedural menuju kultural & substantif.', 'medium'),
('b0000000-0000-4000-8000-050100000000', 'Empat hal yang termasuk dalam Konsensus Dasar Nasional yang perlu diangkat kembali menurut modul ini adalah Pancasila, UUD Negara RI Tahun 1945, Bhinneka Tunggal Ika, dan...', 'Negara Kesatuan Republik Indonesia (NKRI)', 'Garis-Garis Besar Haluan Negara (GBHN)', 'Wawasan Nusantara semata', 'Konvensi ketatanegaraan', null, 'A', 'Konsensus Dasar Nasional yang perlu diangkat kembali: falsafah Pancasila, UUD Negara RI Tahun 1945, semboyan Bhinneka Tunggal Ika, dan prinsip Negara Kesatuan Republik Indonesia (NKRI).', 'easy'),
('b0000000-0000-4000-8000-050200000000', 'Siapa yang mengusulkan nama "Pancasila" sebagai dasar negara pada sidang pertama BPUPKI, dan pada tanggal berapa?', 'Mr. Moh. Yamin, 29 Mei 1945', 'Ir. Soekarno, 1 Juni 1945', 'Prof. R. Soepomo, 31 Mei 1945', 'Drs. Moh. Hatta, 22 Juni 1945', null, 'B', 'Nama "Pancasila" sebagai dasar negara diusulkan Ir. Soekarno pada sidang pertama BPUPKI tanggal 1 Juni 1945, dan disetujui peserta sidang.', 'easy'),
('b0000000-0000-4000-8000-050200000000', 'Dalam kitab Sutasoma karya Mpu Tantular, istilah Pancasila memiliki arti...', 'Lima kesatuan wilayah Nusantara', 'Lima dasar negara modern', 'Berbatu sendi yang lima, pelaksanaan kesusilaan yang lima', 'Lima prinsip pemerintahan kerajaan', null, 'C', 'Dalam Sutasoma, Pancasila berarti "berbatu sendi yang lima, pelaksanaan kesusilaan yang lima". Istilah ini juga tercatat dalam Negara Kertagama karya Mpu Prapanca.', 'medium'),
('b0000000-0000-4000-8000-050200000000', 'Prof. Dr. Notonegoro membagi nilai menjadi tiga jenis. Nilai yang berguna bagi rohani manusia (terbagi menjadi kebenaran, keindahan, kebaikan-moral, dan religius) disebut nilai...', 'Sosiologis', 'Material', 'Vital', 'Kerohanian', null, 'D', 'Prof. Dr. Notonegoro membagi nilai menjadi Material (berguna bagi unsur manusia), Vital (berguna untuk aktivitas), dan Kerohanian (berguna bagi rohani, terbagi 4: kebenaran/akal, keindahan/rasa, kebaikan-moral, religius/kepercayaan). Pancasila tergolong nilai kerohanian yang mengakui nilai material & vital secara seimbang.', 'medium'),
('b0000000-0000-4000-8000-050200000000', 'Urutan tanggal yang benar terkait perumusan dan pengesahan Pancasila adalah...', 'Pidato Soekarno usulkan Pancasila (1 Juni 1945) - Piagam Jakarta oleh Panitia Sembilan (22 Juni 1945) - Pengesahan Pancasila oleh PPKI (18 Agustus 1945)', 'Piagam Jakarta (22 Juni 1945) - Pidato Soekarno (1 Juni 1945) - Pengesahan PPKI (17 Agustus 1945)', 'Pengesahan PPKI (18 Agustus 1945) - Pidato Soekarno (1 Juni 1945) - Piagam Jakarta (22 Juni 1945)', 'Pidato Soepomo (31 Mei 1945) - Pengesahan PPKI (18 Agustus 1945) - Piagam Jakarta (22 Juni 1945)', null, 'A', 'Urutan yang benar: Ir. Soekarno mengusulkan nama Pancasila pada 1 Juni 1945; Panitia Sembilan menghasilkan Piagam Jakarta pada 22 Juni 1945; Pancasila disahkan sebagai dasar negara oleh PPKI pada 18 Agustus 1945 (setelah 7 kata dalam sila pertama dihapus).', 'hard'),
('b0000000-0000-4000-8000-050200000000', 'Pada sidang PPKI tanggal 18 Agustus 1945, tujuh kata "dengan kewajiban menjalankan syariat Islam bagi pemeluk-pemeluknya" dihapus dari sila pertama Piagam Jakarta setelah Drs. Moh. Hatta berunding dengan beberapa tokoh. Siapakah salah satu tokoh yang diajak berunding tersebut?', 'Mr. Moh. Yamin', 'K.H. Wachid Hasyim', 'Radjiman Wediodiningrat', 'Jenderal Terauchi', null, 'B', 'Drs. Moh. Hatta berunding dengan K.H. Wachid Hasyim, Ki Bagus Hadikusumo, Mr. Kasman Singadimedjo, dan Mr. Teuku M. Hasan, sehingga disepakati menghapus 7 kata tersebut dan sila pertama menjadi "Ketuhanan Yang Maha Esa".', 'hard'),
('b0000000-0000-4000-8000-050300000000', 'Setelah amandemen, pasal-pasal UUD 1945 terdiri dari berapa Bab dan berapa Pasal (tidak termasuk Aturan Peralihan dan Aturan Tambahan)?', '21 Bab dan 84 Pasal', '16 Bab dan 71 Pasal', '20 Bab dan 73 Pasal', '18 Bab dan 37 Pasal', null, 'C', 'Pasal-pasal UUD 1945 setelah amandemen terdiri dari 20 Bab (Bab I-XVI) dan 73 pasal (Pasal 1-37), ditambah 3 pasal Aturan Peralihan dan 2 pasal Aturan Tambahan. Bab IV tentang DPA telah dihapus.', 'medium'),
('b0000000-0000-4000-8000-050300000000', 'Ketentuan bahwa Negara Indonesia adalah Negara Kesatuan yang berbentuk Republik, dan bentuk NKRI tidak dapat diubah, diatur berturut-turut dalam pasal berapa?', 'Pasal 4 ayat (1) dan Pasal 7', 'Pasal 1 ayat (2) dan Pasal 18B ayat (2)', 'Pasal 18 ayat (1) dan Pasal 25A', 'Pasal 1 ayat (1) dan Pasal 37 ayat (5)', null, 'D', 'Pasal 1 ayat (1) menyatakan "Negara Indonesia ialah Negara Kesatuan, yang berbentuk Republik". Pasal 37 ayat (5) menegaskan bahwa bentuk NKRI tidak dapat diubah.', 'medium'),
('b0000000-0000-4000-8000-050300000000', 'Lembaga negara manakah yang lahir sebagai hasil amandemen UUD 1945 (tidak ada dalam struktur ketatanegaraan sebelum amandemen)?', 'DPD, MK, dan KY', 'MPR, DPR, dan MA', 'BPK dan Presiden', 'DPA dan KPU', null, 'A', 'Lembaga baru hasil amandemen UUD 1945 adalah DPD (Dewan Perwakilan Daerah), MK (Mahkamah Konstitusi), dan KY (Komisi Yudisial). Sebaliknya, DPA (Dewan Pertimbangan Agung) justru dihapus pada Perubahan Keempat.', 'medium'),
('b0000000-0000-4000-8000-050300000000', 'Manakah urutan periodisasi konstitusi Indonesia yang benar setelah kemerdekaan?', 'Konstitusi RIS (1945-1949) - UUD 1945 (1949-1950) - UUDS 1950 (1950-1959) - UUD 1945 kembali berlaku 1966', 'UUD 1945 (1945-1949) - Konstitusi RIS (1949-1950) - UUDS 1950 (1950-1959) - UUD 1945 kembali berlaku sejak Dekrit Presiden 5 Juli 1959', 'UUDS 1950 (1945-1949) - UUD 1945 (1949-1959) - Konstitusi RIS (1959-1966)', 'UUD 1945 (1945-1959) - UUDS 1950 (1959-1966) - Konstitusi RIS (1966-sekarang)', null, 'B', 'Urutan yang benar: UUD 1945 berlaku 18 Agustus 1945 - 27 Desember 1949; Konstitusi RIS berlaku 27 Desember 1949 - 17 Agustus 1950; UUDS 1950 berlaku 17 Agustus 1950 - 5 Juli 1959; kemudian melalui Dekrit Presiden 5 Juli 1959, UUD 1945 diberlakukan kembali.', 'hard'),
('b0000000-0000-4000-8000-050300000000', 'Perubahan Ketiga UUD 1945 yang ditetapkan pada 9 November 2001 menghasilkan perubahan penting, yaitu...', 'Penghapusan Dewan Pertimbangan Agung (DPA)', 'Pembatasan masa jabatan Presiden maksimal 2 periode', 'Presiden dan Wakil Presiden dipilih langsung oleh rakyat, serta lahirnya DPD, MK, dan KY', 'Perubahan Pasal 33 tentang sistem ekonomi', null, 'C', 'Perubahan Ketiga (Sidang Tahunan MPR 2001, ditetapkan 9 November 2001) antara lain menetapkan bahwa MPR tidak lagi memilih Presiden-Wapres (hanya melantik), Presiden-Wapres dipilih langsung rakyat, serta lahirnya DPD, MK, dan KY. Pembatasan masa jabatan Presiden ada di Perubahan Pertama (1999), sedangkan penghapusan DPA ada di Perubahan Keempat (2002).', 'hard'),
('b0000000-0000-4000-8000-050400000000', 'Peristiwa apa yang menjadi tonggak sejarah "Kebangkitan Nasional" dalam kesadaran kebangsaan Indonesia, dan kapan terjadi?', 'Pembentukan BPUPKI, 29 April 1945', 'Sumpah Pemuda, 28 Oktober 1928', 'Proklamasi Kemerdekaan, 17 Agustus 1945', 'Berdirinya Budi Utomo, 20 Mei 1908', null, 'D', 'Budi Utomo yang berdiri pada 20 Mei 1908 menjadi tonggak sejarah awal Kebangkitan Nasional dalam kesadaran kebangsaan Indonesia.', 'easy'),
('b0000000-0000-4000-8000-050400000000', 'Menurut Prof. Muladi (mantan Gubernur Lemhannas), wawasan kebangsaan adalah cara pandang bangsa Indonesia mengenai diri dan lingkungannya yang mengutamakan...', 'Kesatuan dan persatuan wilayah, dengan integrasi nasional yang bersifat kultural', 'Kepentingan kelompok/golongan di atas kepentingan nasional', 'Otonomi daerah tanpa keterlibatan pemerintah pusat', 'Keseragaman budaya dan bahasa di seluruh wilayah', null, 'A', 'Prof. Muladi menyatakan wawasan kebangsaan adalah cara pandang bangsa Indonesia mengenai diri dan lingkungannya, mengutamakan kesatuan & persatuan wilayah; integrasi nasional bersifat kultural, mencakup kesatuan ideologi, politik, sosial budaya, ekonomi, dan hankam.', 'medium'),
('b0000000-0000-4000-8000-050400000000', 'Berikut ini adalah bukti bahwa wawasan kebangsaan Indonesia menolak adanya warga kelas satu dan kelas dua, KECUALI...', 'Bahasa nasional dipilih dari bahasa Melayu, bukan bahasa Jawa yang mayoritas', 'Bahasa Jawa dijadikan bahasa nasional karena penuturnya mayoritas', 'Sumpah Pemuda memadukan kebhinekaan dengan ketunggalikaan', 'Kemajemukan suku, adat, budaya, dan agama tetap dihormati', null, 'B', 'Justru sebaliknya, bahasa nasional Indonesia dipilih dari bahasa Melayu (berkembang jadi Bahasa Indonesia), bukan bahasa Jawa meskipun penuturnya mayoritas -- ini menjadi bukti tidak adanya warga kelas satu/dua di Indonesia.', 'medium'),
('b0000000-0000-4000-8000-050400000000', 'Dasar hukum yang mengatur bahwa ASN wajib bersumpah setia dan taat pada Pancasila, UUD 1945, negara, dan pemerintah, serta mengutamakan kepentingan negara di atas kepentingan pribadi/golongan adalah...', 'Permenpan-RB No. 38 Tahun 2017', 'PP No. 11 Tahun 2017', 'UU No. 5 Tahun 2014 Pasal 66 ayat (1)-(2)', 'KMK No. 954/KMK.01/2019', null, 'C', 'Fungsi ASN sebagai perekat dan pemersatu bangsa berdasar UU No. 5 Tahun 2014 Pasal 66 ayat (1)-(2): ASN wajib sumpah setia dan taat pada Pancasila, UUD 1945, negara, dan pemerintah, serta mengutamakan kepentingan negara di atas kepentingan pribadi/golongan.', 'medium'),
('b0000000-0000-4000-8000-050400000000', 'Dalam 5 Level Profisiensi Kompetensi Sosial Kultural ASN (Permenpan-RB No. 38 Tahun 2017 & KMK No. 954/KMK.01/2019), level manakah yang berlaku untuk pejabat eselon I dan fungsional utama, dengan deskripsi "menjadi wakil pemerintah membangun hubungan sosial psikologis dengan masyarakat"?', 'Level 1 (paham/dalam pengembangan)', 'Level 4 (mumpuni)', 'Level 3 (menengah)', 'Level 5 (ahli)', null, 'D', 'Level 5 (ahli) untuk eselon I dan fungsional utama: menjadi wakil pemerintah membangun hubungan sosial psikologis dengan masyarakat. Level 4 (mumpuni) untuk eselon II & fungsional madya: mendayagunakan perbedaan secara konstruktif-kreatif untuk efektivitas organisasi.', 'hard'),
('b0000000-0000-4000-8000-050500000000', 'Konvensi hukum laut internasional yang menjadi rujukan satu kesatuan teritori NKRI dari Sabang sampai Merauke, Miangas sampai Rote adalah...', 'UNCLOS 1982', 'Deklarasi Djuanda 1957', 'Konvensi Wina 1969', 'Piagam PBB 1945', null, 'A', 'Makna NKRI mencakup satu kesatuan teritori sesuai UNCLOS 1982 (United Nations Convention on the Law of the Sea), dari Sabang-Merauke, Miangas-Rote.', 'medium'),
('b0000000-0000-4000-8000-050500000000', 'Satu kesatuan bangsa dalam makna NKRI merujuk pada peristiwa sejarah apa?', 'Proklamasi Kemerdekaan 1945', 'Sumpah Pemuda 1928', 'Kongres Pemuda I 1926', 'Dekrit Presiden 1959', null, 'B', 'Makna NKRI mencakup satu kesatuan bangsa yang berlandaskan Sumpah Pemuda 1928.', 'easy'),
('b0000000-0000-4000-8000-050500000000', 'Pasal berapa dalam UUD 1945 yang menegaskan bahwa bentuk negara kesatuan tidak dapat diubah (final) dan tidak pernah diubah sejak amandemen?', 'Pasal 25A dan Pasal 26', 'Pasal 18 ayat (1) dan Pasal 18B ayat (2)', 'Pasal 1 ayat (1) dan Pasal 37 ayat (5)', 'Pasal 30 ayat (1) dan Pasal 33', null, 'C', 'Pasal 1 ayat (1) UUD 1945 tidak pernah diubah sejak amandemen, sebagai komitmen MPR mempertahankan NKRI; Pasal 37 ayat (5) menegaskan bentuk negara kesatuan tidak dapat diubah = bentuk final.', 'medium'),
('b0000000-0000-4000-8000-050500000000', 'Wawasan kebangsaan, sebagaimana ditegaskan pada bab penutup, tidak memberi tempat pada sikap...', 'Penghargaan harkat dan martabat manusia', 'Kesetiakawanan sosial', 'Cinta tanah air dan bangsa', 'Patriotisme yang licik/picik', null, 'D', 'Wawasan kebangsaan tidak memberi tempat pada patriotisme yang licik/picik; cinta tanah air diarahkan pula pada kepentingan seluruh umat manusia (hubungan antar ras/bangsa/negara).', 'easy'),
('b0000000-0000-4000-8000-050500000000', 'Manakah pernyataan yang PALING TEPAT menggambarkan makna NKRI menurut bab penutup modul ini?', 'NKRI mencakup satu kesatuan ideologi (Pancasila), satu kesatuan politik, ekonomi, budaya nasional, serta satu sistem pertahanan keamanan yang khas', 'NKRI hanya berarti satu kesatuan wilayah geografis semata tanpa aspek ideologi', 'NKRI memberi ruang bagi masing-masing daerah membentuk ideologi tersendiri', 'NKRI adalah konsep yang dapat diubah sewaktu-waktu melalui referendum daerah', null, 'A', 'Makna NKRI meliputi satu kesatuan teritori, satu kesatuan bangsa, satu kesatuan kepemilikan sumber kekayaan alam, satu kesatuan ideologi (Pancasila), satu kesatuan politik nasional, satu kesatuan perekonomian nasional, satu kesatuan budaya nasional, dan satu sistem pertahanan keamanan nasional yang khas.', 'medium')
